import { ZkiraClient } from '@zkira/sdk'
import { Connection, PublicKey } from '@solana/web3.js'

const connection = new Connection('https://api.mainnet-beta.solana.com')
const wallet = // Your wallet adapter

const client = new ZkiraClient({
  connection,
  wallet,
  cluster: 'mainnet-beta' // or 'devnet'
})

const USDC_MINT = new PublicKey('EPjFWdd5AufqSSqeM2qN1xzybapC8G4wEGGkZwyTDt1v')

const { link, escrow } = await client.createPaymentLink({
  amount: 1_000_000_000, // 1000 USDC (6 decimals)
  tokenMint: USDC_MINT,
  expirySeconds: 3600 // Optional: expires in 1 hour
})

console.log('Payment Link:', link)
console.log('Escrow Address:', escrow.toString())

const status = await client.getEscrowStatus(escrow)

if (status.state === 'Claimed') {
  console.log('Payment claimed at:', status.claimedAt)
  console.log('Claimed by:', status.recipient?.toString())
} else if (status.state === 'Active') {
  console.log('Payment waiting to be claimed')
} else if (status.state === 'Refunded') {
  console.log('Payment refunded to sender')
}

// Recipient claims payment privately
const escrowAddress = 'ABC123...'

const txSignature = await client.claimStealth({ escrowAddress })
console.log('Claim transaction:', txSignature)

import { ShieldedPoolClient } from '@zkira/sdk'
import { Connection, PublicKey } from '@solana/web3.js'

const SHIELDED_POOL_PROGRAM_ID = new PublicKey('6g5RquPcpe81VzB6CtmuS8pzbXs7nZ5CT7gZt4fLKedx')
const USDC_MINT = new PublicKey('EPjFWdd5AufqSSqeM2qN1xzybapC8G4wEGGkZwyTDt1v')

const poolClient = new ShieldedPoolClient(connection, wallet, {
  programId: SHIELDED_POOL_PROGRAM_ID,
  tokenMint: USDC_MINT,
  denomination: 10_000_000 // 10 USDC
})

// Create a shielded deposit (fixed 10 USDC denomination)
const { txSignature, note } = await poolClient.deposit(USDC_MINT)

// IMPORTANT: Save the encrypted note securely
// You need it to withdraw later

// Generate ZK proof and queue withdrawal (~3s proof generation)
const result = await poolClient.withdraw(note, recipientAddress)

// Withdrawal is queued and processed in ~1 hour
// Funds arrive at recipient address via batched processing

import { createPrivateTransport } from '@zkira/sdk'

// Creates Nym mixnet transport, falls back to direct connection
const transport = await createPrivateTransport()

// Pass to any client for IP-level privacy
const poolClient = new ShieldedPoolClient(
  connection, wallet, poolConfig, { transport }
)

interface EscrowState {
  state: 'Active' | 'Claimed' | 'Refunded'
  amount: bigint
  tokenMint: PublicKey
  creator: PublicKey
  createdAt: Date
  claimedAt?: Date
  recipient?: PublicKey
}

interface PaymentLink {
  link: string
  escrow: PublicKey
  expiresAt?: Date
}

interface CreatePaymentOptions {
  amount: number | bigint
  tokenMint?: PublicKey // Defaults to USDC
  expirySeconds?: number // Optional expiry
  memo?: string // Optional memo
}

interface PoolConfig {
  programId: PublicKey
  tokenMint: PublicKey
  denomination: number
}

interface PoolState {
  totalDeposits: number
  pendingWithdrawals: number
  merkleRoot: string
}

interface DepositResult {
  txSignature: string
  note: string // Encrypted note — save securely
}
